import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
import { Game } from '$lib/domain/Game';
import { Sudoku } from '$lib/domain/Sudoku';

// 内部用领域对象管理游戏
function createGameStore() {
  const emptyGrid = Array(SUDOKU_SIZE).fill().map(()=>Array(SUDOKU_SIZE).fill(0));
  const { subscribe, set, update } = writable(new Game(new Sudoku(emptyGrid)));

  return {
    subscribe,
    generate(diff) {
      const g = generateSudoku(diff);
      set(new Game(new Sudoku(g)));
    },
    decodeSencode(code) {
      const g = decodeSencode(code);
      set(new Game(new Sudoku(g)));
    },
    guess(x,y,v) { update(g=>g.guess(y,x,v)); },
    applyHint(x,y) {
      update(g=>{
        hints.useHint();
        const solved = solveSudoku(g.sudoku.getUserGrid());
        return g.guess(y,x,solved[y][x]);
      });
    },
    undo: ()=>update(g=>g.undo()),
    redo: ()=>update(g=>g.redo()),
    getSencode: g=>encodeSudoku(g.sudoku.getUserGrid()),
    get: (g,x,y)=>g.sudoku.getUserGrid()[y][x]
  };
}

const gameStore = createGameStore();

// 完全保留原有导出，UI无感知
export const grid = {
  subscribe: derived(gameStore,g=>g.sudoku.getFixedGrid()).subscribe,
  generate: d=>gameStore.generate(d),
  decodeSencode: c=>gameStore.decodeSencode(c),
  get: (g,x,y)=>gameStore.get({sudoku:{getUserGrid:()=>g}},x,y),
  getSencode: g=>gameStore.getSencode({sudoku:{getUserGrid:()=>g}})
};

export const userGrid = {
  subscribe: derived(gameStore,g=>g.sudoku.getUserGrid()).subscribe,
  set: (pos,v)=>gameStore.guess(pos.x,pos.y,v),
  applyHint: pos=>gameStore.applyHint(pos.x,pos.y)
};

export const invalidCells = derived(gameStore,g=>g.sudoku.getInvalidCellsArray(),[]);

// 给game.js调用撤销重做
export const domainGameApi = {
  undo: gameStore.undo,
  redo: gameStore.redo
};
